```typescript
export function generatorHandler(handler: Handler): void {
  const stdinInterface = readline.createInterface({
    input: process.stdin,
    crlfDelay: Infinity,
  })

  stdinInterface.on('line', async (line: string) => {
    const json = JSON.parse(line)

    if (json.method === 'generate' && json.params) {
      try {
        const result = await handler.onGenerate(json.params)
        respond({
          jsonrpc: '2.0',
          result: result,
          id: json.id,
        })
      } catch (_e) {
        const e = _e as Error
        respond({
          jsonrpc: '2.0',
          error: {
            code: -32000,
            message: e.message,
            data: { stack: e.stack },
          },
          id: json.id,
        })
      }
    }

    if (json.method === 'getManifest') {
      // Handle manifest request...
    }
  })

  process.stdin.resume()
}
```

**Key Points:**
- Uses JSON-RPC over stdin/stderr for communicating with the CLI
- Handlers implement `onGenerate()` and optional `onManifest()` methods
- All generator packages implement the `Handler` interface

