export type BuildOptions = esbuild.BuildOptions & {
  name?: string
  emitTypes?: boolean
  emitMetafile?: boolean
  outbase?: never
}

const DEFAULT_BUILD_OPTIONS = {
  platform: 'node',
  target: 'ES2022',
  logLevel: 'error',
  tsconfig: 'tsconfig.build.json',
  metafile: true,
} as const

function applyDefaults(options: BuildOptions): BuildOptions {
  return {
    ...DEFAULT_BUILD_OPTIONS,
    format: 'cjs',
    outExtension: { '.js': '.js' },
    resolveExtensions: ['.ts', '.js', '.node'],
    entryPoints: glob.sync('./src/**/*.{j,t}s', {
      ignore: ['./src/__tests__/**/*'],
    }),
    mainFields: ['module', 'main'],
    ...options,
    plugins: [
      ...(options.plugins ?? []),
      resolvePathsPlugin,
      fixImportsPlugin,
      tscPlugin(options.emitTypes),
      onErrorPlugin,
    ],
    external: [...(options.external ?? []), ...getProjectExternals(options)],
  }
}

export async function build(options: BuildOptions[]) {
  return transduce.async(
    createBuildOptions(options),
    pipe.async(computeOptions, logStartBuild, addExtensionFormat, addDefaultOutDir, executeEsBuild),
  )
}
```

**Build Pipeline:**
1. Applies defaults (ES2022, node platform, esbuild configs)
2. Applies plugins (tsconfig, type emission, import fixing)
3. Marks dependencies as external based on package.json
4. Builds both ESM and CJS versions with deferred execution
5. Emits type definitions via API Extractor

