import type * as DMMF from '@prisma/dmmf'

/** Maps a Prisma scalar type name to a TypeScript type name. */
export function scalarToTs(type: string): string {
  switch (type) {
    case 'String':
      return 'string'
    case 'Boolean':
      return 'boolean'
    case 'Int':
    case 'Float':
      return 'number'
    case 'BigInt':
      return 'bigint'
    case 'DateTime':
      return 'Date'
    case 'Json':
      return 'unknown'
    case 'Bytes':
      return 'Uint8Array'
    case 'Decimal':
      // Decimal values are serialised as strings over HTTP to avoid precision loss.
      return 'string'
    default:
      // Enum names and relation model names are used verbatim.
      return type
  }
}

/** Converts a Prisma field to its TypeScript type annotation, including list notation. */
export function fieldToTs(field: DMMF.Field): string {
  const base = field.kind === 'object' ? field.type : scalarToTs(field.type)
  return field.isList ? `${base}[]` : base
}

/**
 * Generates a TypeScript interface declaration for a Prisma model.
 *
 * Relation fields (`kind === 'object'`) are omitted: REST responses carry only
 * scalar/enum data unless explicitly expanded, which is outside the scope of the
 * base client generated here.
 */
export function generateModelInterface(model: DMMF.Model): string {
  const lines: string[] = []

  if (model.documentation) {
    lines.push(`/** ${model.documentation} */`)
  }
  lines.push(`export interface ${model.name} {`)

  for (const field of model.fields) {
    if (field.kind === 'object') continue
    const optional = field.isRequired ? '' : '?'
    if (field.documentation) {
      lines.push(`  /** ${field.documentation} */`)
    }
    lines.push(`  ${field.name}${optional}: ${fieldToTs(field)}`)
  }

  lines.push('}')
  return lines.join('\n')
}

/**
 * Generates a TypeScript type alias for the unique-key where input of a model,
 * used by `findUnique`, `update`, and `delete`.
 *
 * The type is derived from `@id` fields first, falling back to `@unique` fields.
 * If neither exists (unusual), an open record type is produced.
 */
export function generateWhereUniqueType(model: DMMF.Model): string {
  const idFields = model.fields.filter((f) => f.isId)
  const candidates = idFields.length > 0 ? idFields : model.fields.filter((f) => f.isUnique)

  if (candidates.length === 0) {
    return `export type ${model.name}WhereUniqueInput = { [key: string]: unknown }`
  }

  const props = candidates.map((f) => `${f.name}: ${scalarToTs(f.type)}`).join('; ')
  return `export type ${model.name}WhereUniqueInput = { ${props} }`
}

/**
 * Generates a TypeScript type alias for the create input of a model.
 *
 * Fields that are read-only (auto-managed by the database) are excluded.
 * Fields without a default value are required; everything else is optional.
 */
export function generateCreateInputType(model: DMMF.Model): string {
  const fields = model.fields.filter((f) => f.kind !== 'object' && !f.isReadOnly)
  const props = fields
    .map((f) => {
      const optional = !f.isRequired || f.hasDefaultValue ? '?' : ''
      return `${f.name}${optional}: ${fieldToTs(f)}`
    })
    .join('; ')
  return `export type ${model.name}CreateInput = { ${props} }`
}

/**
 * Generates a TypeScript type alias for the update input of a model.
 *
 * All mutable scalar/enum fields are optional because updates are partial (PATCH).
 */
export function generateUpdateInputType(model: DMMF.Model): string {
  const fields = model.fields.filter((f) => f.kind !== 'object' && !f.isReadOnly)
  const props = fields.map((f) => `${f.name}?: ${fieldToTs(f)}`).join('; ')
  return `export type ${model.name}UpdateInput = { ${props} }`
}

/**
 * Derives a kebab-case, pluralised URL path segment from a PascalCase model name.
 *
 * Examples: `"User"` → `"users"`, `"BlogPost"` → `"blog-posts"`.
 */
export function modelToUrlPath(name: string): string {
  return (
    name
      // Insert a hyphen before each uppercase letter that follows a lowercase letter.
      .replace(/([a-z])([A-Z])/g, '$1-$2')
      .toLowerCase() + 's'
  )
}

/**
 * Generates a typed REST client class for one Prisma model with
 * `findMany`, `findUnique`, `create`, `update`, and `delete` methods.
 */
export function generateModelClient(model: DMMF.Model): string {
  const { name } = model
  const urlPath = modelToUrlPath(name)
  const lines: string[] = []

  lines.push(`export class ${name}Client {`)
  lines.push(`  constructor(private readonly baseUrl: string) {}`)
  lines.push('')

  // findMany
  lines.push(`  async findMany(params?: { skip?: number; take?: number }): Promise<${name}[]> {`)
  lines.push(`    const url = new URL(\`\${this.baseUrl}/${urlPath}\`)`)
  lines.push(`    if (params?.skip !== undefined) url.searchParams.set('skip', String(params.skip))`)
  lines.push(`    if (params?.take !== undefined) url.searchParams.set('take', String(params.take))`)
  lines.push(`    const res = await fetch(url.toString())`)
  lines.push(`    if (!res.ok) throw new Error(\`findMany ${name} failed: \${res.statusText}\`)`)
  lines.push(`    return res.json() as Promise<${name}[]>`)
  lines.push(`  }`)
  lines.push('')

  // findUnique
  lines.push(`  async findUnique(where: ${name}WhereUniqueInput): Promise<${name} | null> {`)
  lines.push(`    const id = Object.values(where).join('/')`)
  lines.push(`    const res = await fetch(\`\${this.baseUrl}/${urlPath}/\${id}\`)`)
  lines.push(`    if (res.status === 404) return null`)
  lines.push(`    if (!res.ok) throw new Error(\`findUnique ${name} failed: \${res.statusText}\`)`)
  lines.push(`    return res.json() as Promise<${name}>`)
  lines.push(`  }`)
  lines.push('')

  // create
  lines.push(`  async create(data: ${name}CreateInput): Promise<${name}> {`)
  lines.push(`    const res = await fetch(\`\${this.baseUrl}/${urlPath}\`, {`)
  lines.push(`      method: 'POST',`)
  lines.push(`      headers: { 'Content-Type': 'application/json' },`)
  lines.push(`      body: JSON.stringify(data),`)
  lines.push(`    })`)
  lines.push(`    if (!res.ok) throw new Error(\`create ${name} failed: \${res.statusText}\`)`)
  lines.push(`    return res.json() as Promise<${name}>`)
  lines.push(`  }`)
  lines.push('')

  // update
  lines.push(
    `  async update(where: ${name}WhereUniqueInput, data: ${name}UpdateInput): Promise<${name}> {`,
  )
  lines.push(`    const id = Object.values(where).join('/')`)
  lines.push(`    const res = await fetch(\`\${this.baseUrl}/${urlPath}/\${id}\`, {`)
  lines.push(`      method: 'PATCH',`)
  lines.push(`      headers: { 'Content-Type': 'application/json' },`)
  lines.push(`      body: JSON.stringify(data),`)
  lines.push(`    })`)
  lines.push(`    if (!res.ok) throw new Error(\`update ${name} failed: \${res.statusText}\`)`)
  lines.push(`    return res.json() as Promise<${name}>`)
  lines.push(`  }`)
  lines.push('')

  // delete
  lines.push(`  async delete(where: ${name}WhereUniqueInput): Promise<${name}> {`)
  lines.push(`    const id = Object.values(where).join('/')`)
  lines.push(`    const res = await fetch(\`\${this.baseUrl}/${urlPath}/\${id}\`, {`)
  lines.push(`      method: 'DELETE',`)
  lines.push(`    })`)
  lines.push(`    if (!res.ok) throw new Error(\`delete ${name} failed: \${res.statusText}\`)`)
  lines.push(`    return res.json() as Promise<${name}>`)
  lines.push(`  }`)

  lines.push('}')
  return lines.join('\n')
}

/**
 * Generates the top-level `RestClient` class that exposes a per-model client
 * property for each model in the schema.
 */
export function generateRootClient(modelNames: readonly string[]): string {
  const lines: string[] = []

  lines.push(`/** Typed REST API client for all models in the Prisma schema. */`)
  lines.push(`export class RestClient {`)

  for (const name of modelNames) {
    const prop = name.charAt(0).toLowerCase() + name.slice(1)
    lines.push(`  readonly ${prop}: ${name}Client`)
  }

  lines.push('')
  lines.push(`  constructor(baseUrl: string) {`)
  for (const name of modelNames) {
    const prop = name.charAt(0).toLowerCase() + name.slice(1)
    lines.push(`    this.${prop} = new ${name}Client(baseUrl)`)
  }
  lines.push(`  }`)
  lines.push(`}`)

  return lines.join('\n')
}

/** Returns a standard file header warning that the file is auto-generated. */
export function generateFileHeader(): string {
  return [
    '// This file was auto-generated by @prisma/generator-rest-client.',
    '// Do not edit it directly — re-run `prisma generate` to regenerate.',
    '',
  ].join('\n')
}

