/**
 * Generates the top-level `RestClient` class that exposes a per-model client
 * property for each model in the schema.
 */
export function generateRootClient(modelNames: readonly string[]): string {
  const lines: string[] = []

  lines.push(`/** Typed REST API client for all models in the Prisma schema. */`)
  lines.push(`export class RestClient {`)

  for (const name of modelNames) {
    const prop = name.charAt(0).toLowerCase() + name.slice(1)
    lines.push(`  readonly ${prop}: ${name}Client`)
  }

  lines.push('')
  lines.push(`  constructor(baseUrl: string) {`)
  for (const name of modelNames) {
    const prop = name.charAt(0).toLowerCase() + name.slice(1)
    lines.push(`    this.${prop} = new ${name}Client(baseUrl)`)
  }
  lines.push(`  }`)
  lines.push(`}`)

  return lines.join('\n')
}

/** Returns a standard file header warning that the file is auto-generated. */
export function generateFileHeader(): string {
  return [
    '// This file was auto-generated by @prisma/generator-rest-client.',
    '// Do not edit it directly — re-run `prisma generate` to regenerate.',
    '',
  ].join('\n')
}

