import { generatorHandler } from '@prisma/generator-helper'

import { generate } from './generator'

export { generate }
export {
  fieldToTs,
  generateCreateInputType,
  generateFileHeader,
  generateModelClient,
  generateModelInterface,
  generateRootClient,
  generateUpdateInputType,
  generateWhereUniqueType,
  modelToUrlPath,
  scalarToTs,
} from './template'

generatorHandler({
  onManifest() {
    return {
      prettyName: 'REST Client',
      defaultOutput: './generated/rest-client',
    }
  },
  onGenerate: generate,
})

